func partition(a[]int, lo, hi int) int {
    pivot := a[hi] // 将最后一个值作为分界值
    i := lo - 1
    for j := lo; j < hi; j++
        if a[j] < pivot {
            i++
                a[j], a[i] = a[i], a[j]
        }
    }
    a[i+1], a[hi] = a[hi], a[i+1]
    return i + 1
}

