func quickSort_go2(a[int, lo, hi int, done chan struct{}, depth int) {
    if lo >= hi {
        done <- struct{} {}
    return
} depth--
p := partition(a, lo, hi)
if depth > 0 {
    childDone := make chan struct {}, 2)
    go quickSort_go2(a, lo, p-1, childDone, depth)
    go quickSort_go2(a, p+1, hi, childDone, depth)
